const d = $input.first().json;
const body = d.body || d;
const name = body.name || '';
const biz  = body.businessName || '';
const prof = body.profession || 'professional';
const loc  = body.location ? `, ${body.location}` : '';
const web  = body.website  ? `. Their website is ${body.website}` : '';

const query = `Do a comprehensive digital presence audit for ${name}, a ${prof}${loc}. Their business is called "${biz}"${web}.

Search the entire web and report on:
1. All social media profiles found (LinkedIn, Facebook, Instagram, X/Twitter, TikTok, YouTube, Pinterest) — include URLs and whether they appear active/verified
2. Business listings (Google Business Profile, Yelp, BBB, Zillow, Realtor.com if applicable) — include ratings and review counts
3. Personal website or blog presence
4. Any negative content: complaints, bad reviews, scam reports, BBB disputes, Reddit threads, news articles
5. Any copycat profiles, fake accounts, domain squatters, or impersonators using their name
6. Overall assessment of their digital presence strength

Be specific — include actual URLs where found, star ratings where applicable, and quote any negative content verbatim.`;

return [{ json: { input: d, query } }];

const input     = $('Build Query').first().json.input;
const rawSearch = $input.first().json;
const research  = rawSearch?.choices?.[0]?.message?.content || '';

if (!research) {
  return [{ json: { error: 'Perplexity returned no data', raw: JSON.stringify(rawSearch).slice(0, 300) } }];
}

const prompt = `You are a digital presence analyst. Based on this web research, produce a scored audit report for ${input.name} (${input.businessName}, ${input.profession}).

WEB RESEARCH FINDINGS:
${research}

Return ONLY valid JSON (no markdown, no code fences, no explanation) matching this exact schema:
{
  "overallScore": <integer 0-100>,
  "verdict": "Digital Danger Zone" | "Needs Work" | "Building Momentum" | "Authority Status",
  "summary": "<2-3 sentence plain-English summary of their digital presence>",
  "platforms": [
    { "platform": "<name>", "icon": "<1 emoji>", "found": <boolean>, "url": <string or null>, "score": <0-100>, "verified": <boolean>, "notes": "<short note about their presence here>" }
  ],
  "negativeContent": [
    { "source": "<platform/site name>", "url": <string or null>, "snippet": "<what was said>", "severity": "low" | "medium" | "high", "type": "review" | "complaint" | "news" | "forum" | "other" }
  ],
  "copycats": [
    { "platform": "<name>", "url": <string or null>, "description": "<what was found>", "riskLevel": "low" | "medium" | "high" }
  ],
  "recommendations": [
    { "priority": "immediate" | "high" | "medium" | "low", "category": "<category>", "action": "<specific action to take>", "impact": "<why this matters for leads>", "difficulty": "easy" | "medium" | "hard" }
  ],
  "scannedAt": "${new Date().toISOString()}"
}

Rules:
- Always include these 11 platforms (found=false if not detected): Google Business Profile, LinkedIn, Facebook, Instagram, X (Twitter), TikTok, YouTube, Yelp, Zillow, Realtor.com, Personal Website
- Provide exactly 6 recommendations ranked by priority
- Score: 0-39=Digital Danger Zone, 40-64=Needs Work, 65-84=Building Momentum, 85-100=Authority Status
- Base score on: number of platforms found, profile completeness, review quality, absence of negatives, verified accounts`;

return [{ json: { input, prompt } }];

const raw = $input.first().json?.content?.[0]?.text || '';
let result;
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  result = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { error: 'Failed to parse AI response', raw: raw.slice(0, 500) } }];
}
return [{ json: result }];
